    // Define the main shader function that will be called by the GPU
    void plasmaShader() {
        // Get the fragment position in normalized coordinates (x: -1 to 1)
        vec2 uv = gl_FragCoord.xy / u_resolution.xy;

        // Create a base color and adjust it based on position for an "abstract" look
