        uv += vec2(0.0709, -0.0833) * sin(gl_LocTime * 1.0);

        // Calculate a colorful, abstract mix of base color and UV coordinates
        vec3 finalColor = mix(baseColor, uv, pow(abs(uv.x), 2.0));

        // Mix the result with white to create an inner glow effect (subtle)
        gl_FragColor = mix(vec1(1.0, 1.0, 1.0), vec3(finalColor * 0.95 + baseColor * 0.05), 0.2);

